```class Solution {
public:
    int minimizedStringLength(string s) {
        int res = s.size();
        for (int i = 0; i < s.size(); i++) {
            int left = i, right = i;
            while (left >= 0 && s[left] == s[i]) left--;
            while (right < s.size() && s[right] == s[i]) right++;
            res = min(res, right - left - 1);
        }
        return res;
    }
};```
